const svg=$('#germ-svg'), out=$('#germ-out');
const axs=$('#germ-ax'), ays=$('#germ-ay'), axo=$('#germ-ax-out'), ayo=$('#germ-ay-out');
const W=620, H=360;
const cx=310, cy=180, sc=150;  // scale: 1 unit -> 150px
function toPx(z){ return [cx + sc*z[0], cy - sc*z[1]]; }
function draw(){
  svg.innerHTML='';
  // axes
  svg.appendChild(SVG('line',{x1:20,y1:cy,x2:W-20,y2:cy,stroke:'var(--line)','stroke-width':1}));
  svg.appendChild(SVG('line',{x1:cx,y1:20,x2:cx,y2:H-20,stroke:'var(--line)','stroke-width':1}));
  // original disk D(0,1)
  svg.appendChild(SVG('circle',{cx:cx,cy:cy,r:sc*1,fill:'none',stroke:'var(--violet)','stroke-width':1.5,'stroke-dasharray':'4,4',opacity:0.7}));
  // original center
  svg.appendChild(SVG('circle',{cx:cx,cy:cy,r:3,fill:'var(--violet)'}));
  const t0 = SVG('text',{x:cx+6,y:cy-6,'font-size':12,fill:'var(--violet)'}); t0.textContent='0'; svg.appendChild(t0);
  // singularity at 1
  const p1 = toPx([1,0]);
  svg.appendChild(SVG('circle',{cx:p1[0],cy:p1[1],r:4,fill:'var(--pink)'}));
  const t1 = SVG('text',{x:p1[0]+8,y:p1[1]-8,'font-size':13,fill:'var(--pink)'}); t1.textContent='z=1 (pole)'; svg.appendChild(t1);
  // center a
  const ax=parseFloat(axs.value), ay=parseFloat(ays.value);
  const a=[ax,ay];
  const pa=toPx(a);
  // New radius = |1 - a|
  const R = Math.hypot(1-ax, -ay);
  svg.appendChild(SVG('circle',{cx:pa[0],cy:pa[1],r:sc*R,fill:'none',stroke:'var(--yellow)','stroke-width':1.8}));
  svg.appendChild(SVG('circle',{cx:pa[0],cy:pa[1],r:4,fill:'var(--yellow)'}));
  const ta = SVG('text',{x:pa[0]+6,y:pa[1]-8,'font-size':12,fill:'var(--yellow)'}); ta.textContent='a'; svg.appendChild(ta);
  // legend
  axo.textContent = 'Re a = ' + ax.toFixed(2);
  ayo.textContent = 'Im a = ' + ay.toFixed(2);
  // Does new disk cover points outside |z|=1?
  const reachesOut = R > (1 - Math.hypot(ax,ay)) + 0.01;
  const excess = Math.max(0, R - (1 - Math.hypot(ax,ay)));
  out.textContent =
    'Re-expansion of 1/(1-z) at a gives a series with radius R = |1-a| = ' + R.toFixed(3) + '.\n' +
    'Distance from a to ∂D(0,1): ' + (1 - Math.hypot(ax,ay)).toFixed(3) + '.\n' +
    (reachesOut
      ? 'The new disk ESCAPES the original — continuation reaches points outside |z|<1, excess radius ≈ ' + excess.toFixed(3) + '.'
      : 'The new disk lies inside the original — no new ground covered yet.');
}
axs.addEventListener('input',draw);
ays.addEventListener('input',draw);
draw();

