const svg=$('#chain-svg'), out=$('#chain-out'), tin=$('#chain-t'), tout=$('#chain-tout');
const W=620, H=360, cx=310, cy=180, sc=130;
function toPx(z){ return [cx + sc*z[0], cy - sc*z[1]]; }
// path goes from z = -0.7 to z = +0.9, straight line, aiming toward the pole at z=1
function pathAt(t){ return [-0.7 + t*1.6, 0.2]; }
function draw(){
  svg.innerHTML='';
  // axes
  svg.appendChild(SVG('line',{x1:20,y1:cy,x2:W-20,y2:cy,stroke:'var(--line)','stroke-width':1}));
  svg.appendChild(SVG('line',{x1:cx,y1:20,x2:cx,y2:H-20,stroke:'var(--line)','stroke-width':1}));
  // pole at z=1
  const p1 = toPx([1,0]);
  svg.appendChild(SVG('circle',{cx:p1[0],cy:p1[1],r:5,fill:'var(--pink)'}));
  const t1 = SVG('text',{x:p1[0]+8,y:p1[1]-8,'font-size':13,fill:'var(--pink)'}); t1.textContent='z=1 (pole)'; svg.appendChild(t1);
  // full path
  const P0=toPx(pathAt(0)), P1=toPx(pathAt(1));
  svg.appendChild(SVG('line',{x1:P0[0],y1:P0[1],x2:P1[0],y2:P1[1],stroke:'var(--mute)','stroke-width':1,'stroke-dasharray':'3,3'}));
  // chain of disks: greedy — always jump to the boundary of the current disk
  const t = parseFloat(tin.value);
  const maxT = t;
  const centers = [];
  let cur = 0;
  centers.push(pathAt(0));
  let safety = 0;
  while(cur < maxT && safety < 200){
    safety++;
    const c = pathAt(cur);
    const R = Math.hypot(1-c[0], -c[1]);  // radius of convergence when expanded at c
    // step length along path in world units: path speed is 1.6 per unit t
    // step in t such that distance = 0.85 R
    const stepDist = 0.85 * R;
    const step = Math.min(maxT - cur, stepDist / 1.6);
    cur += step;
    if(step < 1e-4) break;
    centers.push(pathAt(cur));
  }
  // draw disks
  centers.forEach((c, k) => {
    const pc = toPx(c);
    const R = Math.hypot(1-c[0], -c[1]);
    const color = k === centers.length-1 ? 'var(--yellow)' : 'var(--blue)';
    const op = k === centers.length-1 ? 0.28 : 0.12;
    svg.appendChild(SVG('circle',{cx:pc[0],cy:pc[1],r:sc*R,fill:color,'fill-opacity':op,stroke:color,'stroke-width':1,opacity:0.8}));
    svg.appendChild(SVG('circle',{cx:pc[0],cy:pc[1],r:3,fill:color}));
  });
  // current position marker
  const ct = pathAt(t), pct = toPx(ct);
  svg.appendChild(SVG('circle',{cx:pct[0],cy:pct[1],r:5,fill:'var(--green)',stroke:'#000','stroke-width':1}));
  const tx = SVG('text',{x:pct[0]+8,y:pct[1]+16,'font-size':12,fill:'var(--green)'}); tx.textContent='γ(t)'; svg.appendChild(tx);
  // readout
  tout.textContent = 't = ' + t.toFixed(2);
  const lastC = centers[centers.length-1];
  const lastR = Math.hypot(1-lastC[0], -lastC[1]);
  out.textContent =
    'Chain length: ' + centers.length + ' disks.\n' +
    'Current radius at γ(t): R = |1 − γ(t)| = ' + lastR.toFixed(3) + '.\n' +
    (t > 0.95
      ? 'Near the pole z=1 the radii shrink — but the chain still continues f = 1/(1−z).'
      : 'Each re-expansion step jumps ≈ 0.85·R along the path; the chain advances.');
}
tin.addEventListener('input',draw);
draw();

