draw();

const svg=$('#mono-svg'), out=$('#mono-out'), tin=$('#mono-t'), tout=$('#mono-tout');
const W=620, H=360;
// LEFT: z-plane with loop | RIGHT: Im log plot
const L = {cx:170, cy:180, sc:110};
const R = {x0:360, y0:330, xw:230, yh:280};  // plot area
function toL(z){ return [L.cx + L.sc*z[0], L.cy - L.sc*z[1]]; }
function draw(){
  svg.innerHTML='';
  const tmax = parseFloat(tin.value);  // number of turns (0..2)
  // --- left: z plane ---
  // axes
  svg.appendChild(SVG('line',{x1:40,y1:L.cy,x2:320,y2:L.cy,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:L.cx,y1:50,x2:L.cx,y2:310,stroke:'var(--line)'}));
  // branch point at 0
  svg.appendChild(SVG('circle',{cx:L.cx,cy:L.cy,r:5,fill:'var(--pink)'}));
  const t0 = SVG('text',{x:L.cx+8,y:L.cy-8,'font-size':12,fill:'var(--pink)'}); t0.textContent='0'; svg.appendChild(t0);
  // unit circle dashed
  svg.appendChild(SVG('circle',{cx:L.cx,cy:L.cy,r:L.sc,fill:'none',stroke:'var(--mute)','stroke-width':1,'stroke-dasharray':'3,3'}));
  // the traced arc
  const arcPts = [];
  const N = Math.max(6, Math.round(200 * tmax));
  for(let k=0;k<=N;k++){
    const tt = tmax * k / N;
    const theta = 2*Math.PI * tt;
    arcPts.push(toL([Math.cos(theta), Math.sin(theta)]));
  }
  let dpath = 'M ' + arcPts[0][0] + ' ' + arcPts[0][1];
  for(let k=1;k<arcPts.length;k++) dpath += ' L ' + arcPts[k][0] + ' ' + arcPts[k][1];
  svg.appendChild(SVG('path',{d:dpath, stroke:'var(--yellow)','stroke-width':2,fill:'none'}));
  // endpoint marker
  const ep = arcPts[arcPts.length-1];
  svg.appendChild(SVG('circle',{cx:ep[0],cy:ep[1],r:5,fill:'var(--yellow)',stroke:'#000'}));
  // starting point
  const sp = toL([1,0]);
  svg.appendChild(SVG('circle',{cx:sp[0],cy:sp[1],r:4,fill:'var(--blue)'}));
  const ts = SVG('text',{x:sp[0]+6,y:sp[1]+16,'font-size':11,fill:'var(--blue)'}); ts.textContent='z₀=1'; svg.appendChild(ts);
  const tl = SVG('text',{x:80,y:70,'font-size':12,fill:'var(--mute)'}); tl.textContent='z-plane'; svg.appendChild(tl);

  // --- right: Im log(z) vs t ---
  // axes
  svg.appendChild(SVG('line',{x1:R.x0,y1:R.y0,x2:R.x0+R.xw,y2:R.y0,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:R.x0,y1:R.y0,x2:R.x0,y2:R.y0-R.yh,stroke:'var(--line)'}));
  // y-axis ticks at 0, 2pi, 4pi
  const ymax = 4*Math.PI + 1;
  function ty(y){ return R.y0 - (y/ymax)*R.yh; }
  [0, 2*Math.PI, 4*Math.PI].forEach(yv => {
    const yy = ty(yv);
    svg.appendChild(SVG('line',{x1:R.x0-4,y1:yy,x2:R.x0,y2:yy,stroke:'var(--line)'}));
    const tx = SVG('text',{x:R.x0-8,y:yy+4,'font-size':10,fill:'var(--mute)','text-anchor':'end'});
    tx.textContent = (yv===0?'0': (yv/Math.PI).toFixed(0) + 'π');
    svg.appendChild(tx);
  });
  // x-axis ticks at 0, 1, 2 turns
  [0,1,2].forEach(xv => {
    const xx = R.x0 + (xv/2)*R.xw;
    svg.appendChild(SVG('line',{x1:xx,y1:R.y0,x2:xx,y2:R.y0+4,stroke:'var(--line)'}));
    const tx = SVG('text',{x:xx,y:R.y0+16,'font-size':10,fill:'var(--mute)','text-anchor':'middle'});
    tx.textContent = xv + ' turn' + (xv===1?'':'s');
    svg.appendChild(tx);
  });
  // curve: Im log(z(t)) = 2π t as a straight line
  const Nc = Math.max(6, Math.round(200 * tmax));
  let cd = '';
  for(let k=0;k<=Nc;k++){
    const tt = tmax * k / Nc;
    const yv = 2*Math.PI*tt;
    const xx = R.x0 + (tt/2)*R.xw;
    const yy = ty(yv);
    cd += (k===0?'M':'L') + xx + ' ' + yy + ' ';
  }
  svg.appendChild(SVG('path',{d:cd,stroke:'var(--yellow)','stroke-width':2,fill:'none'}));
  // mark 2π level
  const y2pi = ty(2*Math.PI);
  svg.appendChild(SVG('line',{x1:R.x0,y1:y2pi,x2:R.x0+R.xw,y2:y2pi,stroke:'var(--pink)','stroke-width':1,'stroke-dasharray':'3,3',opacity:0.6}));
  const lbl = SVG('text',{x:R.x0+R.xw-2,y:y2pi-4,'font-size':11,fill:'var(--pink)','text-anchor':'end'});
  lbl.textContent = 'one full loop → +2πi';
  svg.appendChild(lbl);
  const tr = SVG('text',{x:R.x0+10,y:R.y0-R.yh+8,'font-size':12,fill:'var(--mute)'}); tr.textContent='Im log z(t)'; svg.appendChild(tr);

  tout.textContent = 't = ' + tmax.toFixed(2) + ' turn' + (tmax===1?'':'s');
  const total = 2*Math.PI*tmax;
  out.textContent =
    'After ' + tmax.toFixed(2) + ' loops around 0:\n' +
    '  continued value of log(1) = 0 + i·(' + total.toFixed(3) + ') = i·' + (total/Math.PI).toFixed(3) + 'π.\n' +
    'Monodromy generator: +2πi per loop. On C\\{0} we have π₁=ℤ; log is ℤ-sheeted.';
}
tin.addEventListener('input',draw);
draw();

