const svg=$('#lac-svg'), out=$('#lac-out');
const rs=$('#lac-r'), ts=$('#lac-t'), ns=$('#lac-n');
const ro=$('#lac-ro'), to=$('#lac-to'), no=$('#lac-no');
const W=620, H=360;
// LEFT: z-plane with point and unit circle
const Lp={cx:170, cy:180, sc:110};
// RIGHT: magnitude plot |F(z)| vs r for fixed theta
const Rp={x0:360, y0:320, xw:230, yh:260};
function toL(z){ return [Lp.cx + Lp.sc*z[0], Lp.cy - Lp.sc*z[1]]; }
function partial(r, theta, N){
  let re=0, im=0;
  for(let n=0;n<=N;n++){
    const k = n*n;
    const rho = Math.pow(r, k);
    const ang = k*theta;
    re += rho*Math.cos(ang);
    im += rho*Math.sin(ang);
  }
  return [re,im];
}
function draw(){
  svg.innerHTML='';
  // left axes
  svg.appendChild(SVG('line',{x1:40,y1:Lp.cy,x2:300,y2:Lp.cy,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:Lp.cx,y1:50,x2:Lp.cx,y2:310,stroke:'var(--line)'}));
  // unit circle
  svg.appendChild(SVG('circle',{cx:Lp.cx,cy:Lp.cy,r:Lp.sc,fill:'none',stroke:'var(--pink)','stroke-width':1.2,'stroke-dasharray':'3,3'}));
  // mark some roots of unity
  for(const q of [2,3,4,5,6,7,8,12]){
    for(let p=0;p<q;p++){
      const ang = 2*Math.PI*p/q;
      const pp = toL([Math.cos(ang), Math.sin(ang)]);
      svg.appendChild(SVG('circle',{cx:pp[0],cy:pp[1],r:2,fill:'var(--pink)',opacity:0.7}));
    }
  }
  const r=parseFloat(rs.value), tval=parseFloat(ts.value), N=parseInt(ns.value);
  const theta = 2*Math.PI*tval;
  const z = [r*Math.cos(theta), r*Math.sin(theta)];
  const pz = toL(z);
  svg.appendChild(SVG('circle',{cx:pz[0],cy:pz[1],r:5,fill:'var(--yellow)',stroke:'#000'}));
  const tl = SVG('text',{x:90,y:65,'font-size':11,fill:'var(--mute)'}); tl.textContent='z-plane (singularities dense on unit circle)'; svg.appendChild(tl);

  // right: |F_N(r e^{iθ})| vs r for current θ
  // axes
  svg.appendChild(SVG('line',{x1:Rp.x0,y1:Rp.y0,x2:Rp.x0+Rp.xw,y2:Rp.y0,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:Rp.x0,y1:Rp.y0,x2:Rp.x0,y2:Rp.y0-Rp.yh,stroke:'var(--line)'}));
  // compute curve |F(r' e^{iθ})| for r' in [0,0.995], fixed θ
  const samples = 120;
  let maxVal = 1;
  const pts = [];
  for(let k=0;k<=samples;k++){
    const rp = 0.995 * k/samples;
    const v = partial(rp, theta, N);
    const mag = Math.hypot(v[0], v[1]);
    pts.push([rp, mag]);
    if(mag>maxVal) maxVal = mag;
  }
  // cap to reasonable
  const cap = Math.min(maxVal, 60);
  function px(rp){ return Rp.x0 + (rp/1.0)*Rp.xw; }
  function py(m){ return Rp.y0 - Math.min(m,cap)/cap * Rp.yh; }
  let d='';
  pts.forEach((pt,k)=>{ d += (k===0?'M':'L') + px(pt[0]) + ' ' + py(pt[1]) + ' '; });
  svg.appendChild(SVG('path',{d,stroke:'var(--cyan)','stroke-width':1.8,fill:'none'}));
  // current r marker
  const cv = partial(r, theta, N);
  const cmag = Math.hypot(cv[0],cv[1]);
  const mx = px(r), my = py(cmag);
  svg.appendChild(SVG('circle',{cx:mx,cy:my,r:4,fill:'var(--yellow)',stroke:'#000'}));
  // axis labels
  [0,0.5,1].forEach(xv=>{
    const xx=px(xv);
    svg.appendChild(SVG('line',{x1:xx,y1:Rp.y0,x2:xx,y2:Rp.y0+4,stroke:'var(--line)'}));
    const t = SVG('text',{x:xx,y:Rp.y0+16,'font-size':10,fill:'var(--mute)','text-anchor':'middle'});
    t.textContent = xv.toFixed(xv===0?0:1); svg.appendChild(t);
  });
  const tr = SVG('text',{x:Rp.x0+Rp.xw/2,y:Rp.y0+30,'font-size':11,fill:'var(--mute)','text-anchor':'middle'}); tr.textContent='radius r′'; svg.appendChild(tr);
  const tl2 = SVG('text',{x:Rp.x0+6,y:Rp.y0-Rp.yh+10,'font-size':11,fill:'var(--mute)'}); tl2.textContent='|F_N(r′e^{iθ})|, capped at '+cap.toFixed(0); svg.appendChild(tl2);

  // readouts
  ro.textContent = 'r = ' + r.toFixed(3);
  // detect rational-ish angle
  let nearRat = '';
  for(const q of [2,3,4,5,6,7,8,10,12]){
    for(let p=0;p<q;p++){
      if(Math.abs(tval - p/q) < 0.003){ nearRat = ' (near p/q = '+p+'/'+q+')'; }
    }
  }
  to.textContent = 'θ = ' + (tval===0?'0':(tval*2).toFixed(3)+'π') + nearRat;
  no.textContent = 'N = ' + N;
  out.textContent =
    '|F_N(z)| ≈ ' + cmag.toFixed(3) + '  at z = ' + r.toFixed(3) + '·exp(i·' + (tval*2).toFixed(3) + 'π), N=' + N + '\n' +
    (r>0.985 ? 'Near the boundary the partial sums start to blow up. Try nudging θ to a rational multiple of π — the blow-up is present there too.' :
     nearRat ? 'At roots of unity the partial sums grow like 1/√(1−r); the boundary point is singular.' :
               'Inside the disk F(z) is perfectly holomorphic, but the unit circle is a natural boundary.');
}
