  const tl2 = SVG('text',{x:Rp.x0+6,y:Rp.y0-Rp.yh+10,'font-size':11,fill:'var(--mute)'}); tl2.textContent='|F_N(r′e^{iθ})|, capped at '+cap.toFixed(0); svg.appendChild(tl2);

  // readouts
  ro.textContent = 'r = ' + r.toFixed(3);
  // detect rational-ish angle
  let nearRat = '';
  for(const q of [2,3,4,5,6,7,8,10,12]){
    for(let p=0;p<q;p++){
      if(Math.abs(tval - p/q) < 0.003){ nearRat = ' (near p/q = '+p+'/'+q+')'; }
    }
  }
  to.textContent = 'θ = ' + (tval===0?'0':(tval*2).toFixed(3)+'π') + nearRat;
  no.textContent = 'N = ' + N;
  out.textContent =
    '|F_N(z)| ≈ ' + cmag.toFixed(3) + '  at z = ' + r.toFixed(3) + '·exp(i·' + (tval*2).toFixed(3) + 'π), N=' + N + '\n' +
