const svg=$('#zeta-svg'), out=$('#zeta-out');
const sin=$('#zeta-s'), sout=$('#zeta-so');
const buttons=$$('.z-step');
let step = 0;
const W=620, H=360;
// plot area
const P={x0:80, y0:300, xw:490, yh:240};
// theta function approx
function theta(x){
  // sum_{n in Z} exp(-pi n^2 x). Use |n|<=8 for x>0.1; use transform for x<0.1
  if(x<0.1){
    return theta(1/x) / Math.sqrt(x);
  }
  let s=1;
  for(let n=1;n<=15;n++){
    const t = Math.exp(-Math.PI*n*n*x);
    if(t<1e-16) break;
    s += 2*t;
  }
  return s;
}
function integrand(x, s, variant){
  // variant: 0 = (θ(x)-1)/2 * x^{s/2-1} (original)
  //         1 = same, split show [0,1]∪[1,∞)
  //         2 = (θ(x)-1)/2 * x^{s/2-1} (orig) over [1,∞)
  //         3 = symmetric: (θ(x)-1)/2 * (x^{s/2-1} + x^{(1-s)/2-1}) on [1,∞)
  const th = (theta(x) - 1)/2;
  if(variant===3) return th * (Math.pow(x, s/2-1) + Math.pow(x, (1-s)/2-1));
  return th * Math.pow(x, s/2-1);
}
function draw(){
  svg.innerHTML='';
  sin.disabled = false;
  // axes
  svg.appendChild(SVG('line',{x1:P.x0,y1:P.y0,x2:P.x0+P.xw,y2:P.y0,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:P.x0,y1:P.y0,x2:P.x0,y2:P.y0-P.yh,stroke:'var(--line)'}));
  // x-axis label
  const lx = SVG('text',{x:P.x0+P.xw/2,y:P.y0+32,'font-size':12,fill:'var(--mute)','text-anchor':'middle'});
  lx.textContent = 'x';  svg.appendChild(lx);

  const s = parseFloat(sin.value);
  sout.textContent = 's = ' + s.toFixed(2);

  // x range: log-ish from 0.03 to 5
  const xmin=0.03, xmax=5;
  function xtoPx(x){ return P.x0 + ((x-xmin)/(xmax-xmin))*P.xw; }
  // draw x=1 vertical guide
  const x1p = xtoPx(1);
  svg.appendChild(SVG('line',{x1:x1p,y1:P.y0,x2:x1p,y2:P.y0-P.yh,stroke:'var(--pink)','stroke-width':1,'stroke-dasharray':'3,3',opacity:0.6}));
  const lab1 = SVG('text',{x:x1p+4,y:P.y0-P.yh+12,'font-size':11,fill:'var(--pink)'}); lab1.textContent='x=1'; svg.appendChild(lab1);

  // sample integrand
  const N=200;
  let vals=[]; let maxV=0;
  for(let k=0;k<=N;k++){
    const x = xmin + (xmax-xmin)*k/N;
    const v = (step<=2)
      ? integrand(x, s, 0)
      : (step===3 || step===4)
        ? (x>=1 ? integrand(x, s, 3) : 0)
        : integrand(x, s, 0);
    vals.push([x,v]);
    if(Math.abs(v)>maxV && isFinite(v)) maxV = Math.abs(v);
  }
  if(maxV<0.1) maxV = 0.1;
  function ytoPx(y){ return P.y0 - (y/maxV)*P.yh*0.9; }

  // y-axis ticks
  [0, maxV/2, maxV].forEach(yv=>{
    const yy = ytoPx(yv);
    svg.appendChild(SVG('line',{x1:P.x0-4,y1:yy,x2:P.x0,y2:yy,stroke:'var(--line)'}));
    const tt = SVG('text',{x:P.x0-8,y:yy+4,'font-size':10,fill:'var(--mute)','text-anchor':'end'});
    tt.textContent = yv.toFixed(2); svg.appendChild(tt);
  });

  // shaded region
  if(step>=2){
    // shade x<1 differently from x>=1
    let d1 = 'M ' + xtoPx(vals[0][0]) + ' ' + P.y0;
    let d2 = null;
    for(let k=0;k<vals.length;k++){
      const [x,v] = vals[k];
      if(x<=1){
        d1 += ' L ' + xtoPx(x) + ' ' + ytoPx(v);
      } else {
        if(d2===null){ d2 = 'M ' + xtoPx(x) + ' ' + P.y0 + ' L ' + xtoPx(x) + ' ' + ytoPx(v); }
        else { d2 += ' L ' + xtoPx(x) + ' ' + ytoPx(v); }
      }
    }
    d1 += ' L ' + xtoPx(1) + ' ' + P.y0 + ' Z';
    d2 += ' L ' + xtoPx(xmax) + ' ' + P.y0 + ' Z';
    if(step===2){
      svg.appendChild(SVG('path',{d:d1,fill:'var(--violet)','fill-opacity':0.25,stroke:'var(--violet)','stroke-width':1}));
      svg.appendChild(SVG('path',{d:d2,fill:'var(--cyan)','fill-opacity':0.25,stroke:'var(--cyan)','stroke-width':1}));
    } else {
      // step 3, 4: [0,1) piece folded away, only [1,∞) shown symmetric
      svg.appendChild(SVG('path',{d:d2,fill:'var(--green)','fill-opacity':0.25,stroke:'var(--green)','stroke-width':1.2}));
    }
  } else {
    // single shaded region
    let d = 'M ' + xtoPx(vals[0][0]) + ' ' + P.y0;
    for(const [x,v] of vals) d += ' L ' + xtoPx(x) + ' ' + ytoPx(v);
    d += ' L ' + xtoPx(xmax) + ' ' + P.y0 + ' Z';
    svg.appendChild(SVG('path',{d, fill:'var(--yellow)','fill-opacity':0.22,stroke:'var(--yellow)','stroke-width':1.2}));
  }

  // step-specific caption
  let cap = '';
  if(step===0){
    cap = 'ζ(s) = Σ 1/n^s,  converges only for Re s > 1.';
  } else if(step===1){
    cap = 'Gamma trick: π^{−s/2} Γ(s/2) ζ(s) = ∫₀^∞ (θ(x)−1)/2 · x^{s/2−1} dx.   Shaded = integrand over (0,∞).';
  } else if(step===2){
    cap = 'Split at x=1:  (0,1) violet,  [1,∞) cyan.  The (0,1) piece is the troublesome one for small Re s.';
  } else if(step===3){
    cap = 'Under x→1/x on (0,1) and θ(1/x)=√x·θ(x), the violet piece re-expresses as an integral on [1,∞), producing −1/(s(1−s)) + symmetric integrand on [1,∞).';
  } else if(step===4){
    cap = 'Completed ξ(s) = ½ s(s−1) π^{−s/2} Γ(s/2) ζ(s) is entire, and ξ(s)=ξ(1−s).  Slider changes s; integrand on [1,∞) is MANIFESTLY symmetric under s↦1−s.';
  }
  out.textContent = cap;

  // header text
  const ttl = SVG('text',{x:P.x0, y:40, 'font-size':13, fill:'var(--ink)','font-weight':600});
  ttl.textContent = ['0. ζ(s)=Σ n^{−s}',
                     '1. Mellin via gamma',
                     '2. split at x=1',
                     '3. use θ(1/x)=√x·θ(x)',
                     '4. ξ(s)=ξ(1−s)'][step];
  svg.appendChild(ttl);
}
buttons.forEach(b => b.addEventListener('click', ()=>{
  step = parseInt(b.dataset.step);
  buttons.forEach(x => x.classList.remove('active'));
  b.classList.add('active');
  draw();
}));
sin.addEventListener('input', draw);
draw();

